let verbose = false;

export function setVerbose(v: boolean) { verbose = v; }

export const logger = {
  info: (msg: string) => console.log(`[info] ${msg}`),
  error: (msg: string) => console.error(`[error] ${msg}`),
  debug: (msg: string) => { if (verbose) console.log(`[debug] ${msg}`); },
};

