import { setVerbose } from './logger';

const program = new Command()
  .name('acme')
  .version('1.0.0')
  .description('Acme CLI toolkit')
  .option('-v, --verbose', 'Enable debug logging')
  .hook('preAction', (cmd) => {
    if (cmd.opts().verbose) setVerbose(true);
  });
